// CallARPRefreshStatusForADR for Application Review Page

const websvcName = "ARPRefreshStatusForADR";

// Make the execution to async
const deferred = $.Deferred();

// Call the microservice
const CallServerSide = function () {
  VV.Form.ShowLoadingPanel();

  // Create the form data to send to the microservice
  const formData = [
    {
      name: "Form ID",
      value: VV.Form.DhDocID,
    },
    {
      name: "Related Record ID",
      value: VV.Form.GetFieldValue('Related Record ID')
    },
  ];

  // Convert form data to JSON and prepare the server-side call
  const data = JSON.stringify(formData);
  const requestObject = $.ajax({
    type: "POST",
    url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${websvcName}`,
    contentType: `application/json; charset=utf-8`,
    data: data,
  });

  return requestObject;
};

$.when(CallServerSide()).always(function (resp) {
  let messageData = "";
  let resolvePromise = false;
  let callData = {};

  VV.Form.HideLoadingPanel();

  if (typeof resp.status != "undefined") {
    messageData = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;

    displayErrorModal(messageData);
  } else if (typeof resp.statusCode != "undefined") {
    messageData = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server. This may mean that the servers to run the business logic are not available.`;

    displayErrorModal(messageData);
  } else if (resp.meta.status == "200") {
    if (resp.data[0] !== "undefined") {
      if (resp.data[0] === "Success") {
        resolvePromise = true;
        callData = resp.data[2];
      } else if (resp.data[0] === "Error") {
        messageData = `An error was encountered. ${resp.data[2] || ''}`; 
      } else {
        messageData = `An unhandled response occurred when calling ${websvcName}. The form will not save at this time. Please try again or communicate this issue to support.`;
      }
    } else {
      messageData = "The status of the response returned as undefined.";
    }
  } else {
    messageData = `The following unhandled response occurred while attempting to retrieve data from ${websvcName}: ${resp?.data?.error}`;
  }
  // resolve/reject promise
  if (resolvePromise) {
    deferred.resolve(callData);
  } else {
    deferred.reject({
        message: 'Error',
        messageDetail: messageData
    });
  }
});

return deferred.promise();

// LibGetApplicationReviewPageRelatedData for Application Review Page

const webServiceName = 'LibGetApplicationReviewPageRelatedData';
const formName = 'Application Review Page';
let message; // the message is set below

VV.Form.ShowLoadingPanel();


let deferred = $.Deferred();

function CallServerSide() {
    let formData = []

    // Uncomment the following to add more data to the formData object.
    let moreData = {
       name: 'FPAN Number',
       value: VV.Form.GetFieldValue('FPAN Number')
    };
    formData.push(moreData);

    moreData = {
        name: 'Type',
        value: VV.Form.GetFieldValue('Application Type')
    }
    formData.push(moreData);

    // Parse the data as a JSON string
    const data = JSON.stringify(formData);

    const requestObject = $.ajax({
        type: 'POST',
        url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${webServiceName}`,
        contentType: 'application/json; charset=utf-8',
        data: data,
        success: '',
        error: '',
    });

    return requestObject;
}

$.when(CallServerSide())
    .always(function (resp) {

        let resolvePromise = false;
        let data = {};
        VV.Form.HideLoadingPanel();

        if (typeof resp.status != 'undefined') {
            message = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
        } else if (typeof resp.statusCode != 'undefined') {
            message = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server.  This may mean that the servers to run the business logic are not available.`;
        } else if (resp.meta.status == '200') {
            if (resp.data[0] != undefined) {
                if (resp.data[0] == 'Success') {
                    message = `${formName} has been saved successfully.`;

                    // HANDLE SUCCESS RESPONSE HERE
                    resolvePromise = true;

                    data = resp.data[2]

                } else if (resp.data[0] == 'Error') {
                    message = `An error was encountered. ${resp.data[1]}`;
                    VV.Form.Global.DisplayModal({
                        Title: 'Error',
                        Icon: 'error',
                        HtmlContent: message
                    })
                } else {
                    message = `An unhandled response occurred when calling ${webServiceName}. The form will not save at this time.  Please try again or communicate this issue to support.`;
                    VV.Form.Global.DisplayModal({
                        Title: 'Error',
                        Icon: 'error',
                        HtmlContent: message
                    })
                }
            } else {
                message = 'The status of the response returned as undefined.';
                VV.Form.Global.DisplayModal({
                    Title: 'Error',
                    Icon: 'error',
                    HtmlContent: message
                })
            }
        } else {
            message = `The following unhandled response occurred while attempting to retrieve data on the server side get data logic. ${resp.data.error} <br>`;
            VV.Form.Global.DisplayModal({
                Title: 'Error',
                Icon: 'error',
                HtmlContent: message
            })
        }

        // resolve/reject promise
        if (resolvePromise) {
            Promise.all([
                data.timberHarvest && VV.Form.SetFieldValue('Timber Harvest', data.timberHarvest),
                data.biomass && VV.Form.SetFieldValue('Biomass', data.biomass),
                (data.rockPitExisting || data.rockPitNew) && VV.Form.SetFieldValue('Rock Pit', data.rockPitExisting + data.rockPitNew),
                data.roadConstruction && VV.Form.SetFieldValue('Road Construction', data.roadConstruction),
                data.roadAbandonment && VV.Form.SetFieldValue('Road Abandonment', data.roadAbandonment),
                data.hydraulicProject && VV.Form.SetFieldValue('Hydraulic Project', data.hydraulicProject),
                data.spoilDeposits && VV.Form.SetFieldValue('Spoil Deposits', data.spoilDeposits),
                data.aerialSpray && VV.Form.SetFieldValue('Aerial Spray', data.aerialSpray),
                data.fpanDateOfReceipt && VV.Form.SetFieldValue('FPAN Date of Receipt', data.fpanDateOfReceipt),
                data.renewalStatus && VV.Form.SetFieldValue('old FPAN Renewal Status', data.renewalStatus),
                data.renewalStatus && VV.Form.SetFieldValue('FPAN Renewal Status', data.renewalStatus),
                data.renewalDateOfReceipt && VV.Form.SetFieldValue('FPAN Renewal Date of Receipt', data.renewalDateOfReceipt),
                data.ltaStatus && VV.Form.SetFieldValue('old LTA Step 1 Status', data.ltaStatus),
                data.ltaStatus && VV.Form.SetFieldValue('LTA Step 1 Status', data.ltaStatus),
                data.ltaDateOfReceipt && VV.Form.SetFieldValue('LTA Date of Receipt', data.ltaDateOfReceipt)
            ]).then(() => {
                deferred.resolve();
            });
        } else {
            deferred.reject(message);
        }
    })

return deferred.promise();

/*
 * RemoveSelectedDecisionInformation
 * This is the name of the web service that will be called from the server-side.
 *
 * Note: Make sure that your server-side script is configured to call the web service and handle the response.
 *
 * PARAMETERS:
 *              - SelectedItems: Array (Collection of GUIDs)
 */

const websvcName = "RemoveSelectedDecisionInformation";

const CallServerSide = function () {
  VV.Form.ShowLoadingPanel();

  const formData = [
    {
      name: "Selected Item IDs",
      value: SelectedItems,
    },
    {
      name: "Form ID",
      value: VV.Form.DhDocID,
    }
  ];

  const data = JSON.stringify(formData);
  const requestObject = $.ajax({
    type: "POST",
    url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${websvcName}`,
    contentType: `application/json; charset=utf-8`,
    data: data,
  });

  return requestObject;
};

$.when(CallServerSide()).always(function (resp) {
  VV.Form.HideLoadingPanel();
  let messageData = "";

  if (typeof resp.status != "undefined") {
    messageData = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
    displayErrorModal(messageData);
  } else if (typeof resp.statusCode != "undefined") {
    messageData = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server. This may mean that the servers to run the business logic are not available.`;
    displayErrorModal(messageData);
  } else if (resp.meta.status == "200") {
    if (resp.data[0] != "undefined") {
      if (resp.data[0] == "Success") {
        messageData = `Decision Information (s) removed successfully`;

        VV.Form.Global.DisplayModal({
          Icon: "success",
          Title: "Success",
          HtmlContent: messageData,
        });
      } else if (resp.data[0] == "Error") {
        messageData = `An error was encountered. ${resp.data[1]}`;
        displayErrorModal(messageData);
      } else {
        messageData = `An unhandled response occurred when calling ${websvcName}. The form will not save at this time. Please try again or communicate this issue to support.`;
        displayErrorModal(messageData);
      }
    } else {
      messageData = "The status of the response returned as undefined.";
      displayErrorModal(messageData);
    }
  } else {
    messageData = `The following unhandled response occurred while attempting to retrieve data from ${websvcName}: ${resp?.data?.error}`;
    displayErrorModal(messageData);
  }

  // refresh all RRCs/DGs/DDs on this and parent forms
  VV.Form.Global.RefreshFormElements();
});

function displayErrorModal(messageData) {
  VV.Form.Global.DisplayModal({
    Title: "Error",
    Icon: "error",
    HtmlContent: messageData,
  });
}

const sectionData = {
    "Notification Section": "Cultural Resources: Tribal",
    "Fields": {
        "Tribal Notification Sent To": VV.Form.GetFieldValue("Tribal Notification Sent To"),
        "Date Tribal Notification Sent": VV.Form.GetFieldValue("Date Tribal Notification Sent"),
        "Tribal Meeting Request Received": VV.Form.GetFieldValue("Tribal Meeting Request Received"),
        "Tribal Meeting Occurred": VV.Form.GetFieldValue("Tribal Meeting Occurred"),
        "Tribal Notification Comments": VV.Form.GetFieldValue("Tribal Notification Comments")
    }
}

return Object.values(sectionData.Fields).some(value => value) ? sectionData : "No Fields Present";

//DocumentsUpdate for ARP
/**
 * @param {string} newStatus - New status
 * @param {string} oldStatus - Old Status
 * @param {string} formID - Form ID
 * @param {string} formTemplate - Form Template
 *
 * @returns {Promise} The promise object that will resolve with the response data if successful, or reject with an error message if failed.
 */

const now = new Date().toLocaleString('en-US', {
  timeZone: 'America/Los_Angeles',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: true,
});

const formTemplateType = formTemplate;
const sensitiveSite = false;

const formType = formTemplate;
const fpanNumber = VV.Form.GetFieldValue('FPAN Number');
const relatedRecordId = formID;
const beforeStatusValue = oldStatus;
const statusChange = newStatus;
const statusModifiedBy = VV.Form.FormUserID;
const statusModifiedDate = now;

return Promise.resolve()
  .then(() =>
    VV.Form.Global.CallLibAssociatedDocumentRelationUpdate(formID, formTemplateType, sensitiveSite)
  )
  .then(() =>
    VV.Form.Global.CallLibStatusHistoryCreate(
      formType,
      fpanNumber,
      relatedRecordId,
      beforeStatusValue,
      statusChange,
      statusModifiedBy,
      statusModifiedDate,
      VV.Form.DhDocID
    )
  );

// CallARPClearPDFPackage for Application Review Page

const webServiceName = 'ARPClearPDFPackage';
const deferred = $.Deferred();

function CallServerSide() {
  const data = JSON.stringify([{ name: 'Form ID', value: VV.Form.DhDocID }]);

  const requestObject = $.ajax({
    type: 'POST',
    url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${webServiceName}`,
    contentType: 'application/json; charset=utf-8',
    data: data,
    success: '',
    error: '',
  });
  VV.Form.ShowLoadingPanel();
  return requestObject;
}

$.when(CallServerSide()).always(function (resp) {
  let resolvePromise = false;
  let message;
  VV.Form.HideLoadingPanel();

  if (typeof resp.status != 'undefined') {
    message = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
  } else if (typeof resp.statusCode != 'undefined') {
    message = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server.  This may mean that the servers to run the business logic are not available.`;
  } else if (resp.meta.status == '200') {
    if (resp.data[0] != undefined) {
      if (resp.data[0] == 'Success') {
        resolvePromise = true;
      } else if (resp.data[0] == 'Error') {
        message = `The related application form could not be located. However, you may still complete the form manually. If you require assistance, please contact our support team.`;
      } else {
        message = `An unhandled response occurred when calling ${webServiceName}. The form will not save at this time.  Please try again or communicate this issue to support.`;
      }
    } else {
      message = 'The status of the response returned as undefined.';
    }
  } else {
    message = `The following unhandled response occurred while attempting to retrieve data on the server side get data logic. ${resp.data.error} <br>`;
  }

  // resolve/reject promise
  if (resolvePromise) {
    deferred.resolve('Success');
  } else {
    deferred.reject(message);
  }
});

return deferred.promise();

