/**
 * SearchAssociatedDocs for Application Review Page
 * Filter the Associated documents DG based on search param
 * @param {string} searchTerm - Search Term
 *
 * @returns {Promise} The promise object that will resolve with the response data if successful, or reject with an error message if failed.
 */
const fieldsToSearch = [
  'Document Form Name',
  'Document Form Type',
  'Sensitive Indicator',
  'Document Form Status',
  'Document Create By',
  'Document Create Date',
  'Receipt Date',
  'Document Modify By',
  'Document Modify Date',
];
const filterFieldName = 'Associated Docs Filter';
const doFilter = searchTerm && searchTerm !== '';
let newFilterValue = '1 = 1'; //Resetting filter by default

if (doFilter) {
  let logicalOperator = '';
  newFilterValue = fieldsToSearch.reduce((filterString, field) => {
    filterString += ` ${logicalOperator} [${field}] LIKE '%${searchTerm}%'`;
    logicalOperator = 'OR';
    return filterString;
  }, '');
}

return VV.Form.SetFieldValue(filterFieldName, newFilterValue).then(() => {
  VV.Form.RefreshDataGridControl('DG Associated Documents');
  return Promise.resolve();
});

