if (trimmed && trimmed !== "Select Item" && trimmed !== "") {
  // Use zDD Region to resolve Region to regionCode (dropdown value).
  VV.Form.Global.UseCustomQuery("zDD Region", null, null)
    .then(function (response) {
      if (response && Array.isArray(response)) {
        const byName = response.find(function (r) {
          return (r["region Name"] || "").trim() === trimmed;
        });
        if (byName && byName["region Code"]) {
          regionCode = (byName["region Code"] || "").trim();
        } else {
          const byCode = response.find(function (r) {
            return (r["region Code"] || "").trim() === trimmed;
          });
          if (byCode) {
            regionCode = trimmed;
          }
        }
      }
      createAndRelateForm();
    })
    .catch(function (error) {
      createAndRelateForm();
    });
} else {
  createAndRelateForm();
}

