const templateId = "7e5bd149-4d9a-f011-aabd-9b87e0168116"; // NTC Form
const regionValue = VV.Form.GetFieldValue("Region");
const trimmed = (regionValue && typeof regionValue === "string") ? regionValue.trim() : "";
let regionCode = trimmed;

function createAndRelateForm() {
  const fieldMapping = [
    {
      sourceFieldName: "Record ID",
      sourceFieldValue: VV.Form.DhDocID,
      targetFieldName: "Related Record ID",
    },
    {
      sourceFieldName: "FPAN Number",
      sourceFieldValue: VV.Form.GetFieldValue("FPAN Number"),
      targetFieldName: "FPAN Number WTMF Number",
    },
    {
      sourceFieldName: "Region",
      sourceFieldValue: regionCode,
      targetFieldName: "Region",
    },
  ];

  VV.Form.DoAjaxFormSave().then(() => {
    VV.Form.Global.FillinAndRelateForm(templateId, fieldMapping);
  }).catch(function (error) {
    // Error handling without logging
  });
}

if (trimmed && trimmed !== "Select Item" && trimmed !== "") {
  // Use zDD Region to resolve Region to regionCode (dropdown value).
  VV.Form.Global.UseCustomQuery("zDD Region", null, null)
    .then(function (response) {
      if (response && Array.isArray(response)) {
        const byName = response.find(function (r) {
          return (r["region Name"] || "").trim() === trimmed;
        });
        if (byName && byName["region Code"]) {
          regionCode = (byName["region Code"] || "").trim();
        } else {
          const byCode = response.find(function (r) {
            return (r["region Code"] || "").trim() === trimmed;
          });
          if (byCode) {
            regionCode = trimmed;
          }
        }
      }
      createAndRelateForm();
    })
    .catch(function (error) {
      createAndRelateForm();
    });
} else {
  createAndRelateForm();
}

