  VV.Form.SetFieldValue("Old FPAN Status Flag", true).then(() => {
    VV.Form.Global.DisplayModal({
      HtmlContent: `Do you want to change the current FPA/N Status?`,
      Icon: "question",
      Title: "Update the FPA/N Status History",
      showCancelButton: false,
      allowOutsideClick: false,
      showDenyButton: true,
      ConfirmText: "Yes",
      SecondaryText: "No",
      okFunction: () => {
        Promise.resolve()

          // If Type is LTA-1, then update LTA Status Fields
          .then(() =>
            isLtaStep1 ? updateLtaStep1Status(FPANNewStatus) : Promise.resolve()
          )

          // Update old Status and DataAt
          .then(() =>
            Promise.all([
              VV.Form.SetFieldValue("Old FPAN Status", FPANNewStatus),
              VV.Form.SetFieldValue(
                updatedAtField,
                VV.Form.Global.GetDateUTC()
              ),
            ])
          )

          // Set notification flag to false
          .then(() => VV.Form.SetFieldValue("Old FPAN Status Flag", false))

          // Check if notification for FPAN is needed
          .then(() =>
            VV.Form.SetFieldValue(
              "Forest Practice Notification Needed",
              forestPracticeNotificationNeeded
            )
          )

          // Save the Form
          .then(() =>
            VV.Form.DoAjaxFormSave().catch((e) => {
              throw new Error("saveRevisionError");
            })
          )

          // Update Status on Related Record ID
          .then(() =>
            VV.Form.Template.UpdateStatus(FPANNewStatus, "FPAN", false)
          )

          // Update the related ADR and Status history for Related Record ID
          .then(() =>
            VV.Form.Template.DocumentsUpdate(
              FPANNewStatus,
              FPANOldStatus,
              VV.Form.GetFieldValue("Related Record ID"),
              formType
            )
          )

          // If it is valid, update notification flag
          .then(() =>
            isValidEvent
              ? VV.Form.Template.UpdateNotificationFlag(false)
              : Promise.resolve()
          )

          // Display Success modal
          .then(() => {
            VV.Form.Global.DisplayModal({
              Title: "Success",
              Icon: "success",
              HtmlContent: `${appType} status successfully updated.`,
            });
          })

          .catch((error) => {
            Promise.all([
              VV.Form.SetFieldValue("FPAN Status", FPANOldStatus),
              VV.Form.SetFieldValue("Old FPAN Status", FPANOldStatus),
            ])

              .then(() =>
                isLtaStep1
                  ? updateLtaStep1Status(FPANOldStatus)
                  : Promise.resolve()
              )

              .then(() => {
                console.error("Error updating form:", error);

                // Check if error was due to DoAjaxFormsave or not
                if (error.message === "saveRevisionError") {
                  VV.Form.Global.DisplayModal({
                    Icon: "warning",
                    Title: "Form could not be saved",
                    HtmlContent:
                      "This form could not be saved because it is not the latest version of the record. Please click OK or refresh the page and try again your action.",
                    okFunction: () => window.location.reload(),
