  lowerCaseRoles.includes('office staff') || lowerCaseRoles.includes('vaultaccess');
const isFieldStaff = lowerCaseRoles.includes('field staff');

const promiseArray = [
  VV.Form.SetFieldValue('OnLoad Finished', 'False', true),
  VV.Form.SetFieldValue('old FPAN Renewal Status', FPANRenewalStatus, true),
  VV.Form.SetFieldValue('old LTA Step 1 Status', LTAStep1Status, true),
  VV.Form.SetFieldValue('IsOfficeStaff', isOfficeStaff, true),
