  VV.Form.Template.AutopopulateAPR(),
  VV.Form.Template.AutopopulateHeader(),
  VV.Form.Template.checkExistingPDFPackage(),
  VV.Form.Template.SearchAssociatedDocs(''),
];

const conditionalPromise =
  FPANDataRetrieved === 'false' ? VV.Form.Template.GetFPANData() : Promise.resolve();

Promise.all([...promiseArray, conditionalPromise])
  .then(() => {
    const fpanStatus = VV.Form.GetFieldValue('FPAN Status');
    if (fpanStatus !== 'Select Item') {
      VV.Form.SetFieldValue('Old FPAN Status', fpanStatus);
    }
  })
  .then(() => {
    const dateOfReceiptArray = [
      VV.Form.SetFieldValue('Old FPAN Date of Receipt', VV.Form.GetFieldValue('FPAN Date of Receipt')),
      VV.Form.SetFieldValue('Old LTA Date of Receipt', VV.Form.GetFieldValue('LTA Date of Receipt')),
      VV.Form.SetFieldValue('Old FPAN Renewal Date of Receipt', VV.Form.GetFieldValue('FPAN Renewal Date of Receipt')),
    ];
    return Promise.all([...dateOfReceiptArray]);
  })
  .then(() => VV.Form.Template.UpdateDocumentPath())
  .then(() => VV.Form.SetFieldValue('Auto Populate Done', 'True'))
  .then(() => {
    VV.Form.Template.CallARPRefreshStatusForADR().then(() =>
      VV.Form.RefreshDataGridControl('DG Associated Documents')
    );
  })
  .then(() => {
    if (readOnly) {
      return Promise.resolve();
    } else {
      /* 
       * NOTE: This is the *ONLY* save in this chain of promises. Saving during form load but outside of this chain 
       * can cause errors where SetFieldValues are not fully committed to the database
       */
      return VV.Form.DoAjaxFormSave();
    }
  })
  .finally(() => {
    VV.Form.SetFieldValue('OnLoad Finished', 'True', true)
  });

