            const checkCommunicationFlag = validStatusForNotificationFlag.includes(RenewalNewStatus);

            // Initializate on change process
            Promise.resolve()

                // Update FPAN Header Statuses
                .then(() => {
                    if (RenewalNewStatus.toLowerCase() === "renewal accepted") {
                        return updateHeaderFpanStatus("Renewed");
                    }
