                .then(() => VV.Form.SetFieldValue('Forest Practice Notification Needed', forestPracticeNotificationNeeded))

                // Save the Form
                .then(() => 
                VV.Form.DoAjaxFormSave()
                    .catch(e => {
                    throw new Error('saveRevisionError');
                    })
                )

                // Update related Form Status
                .then(() => VV.Form.Template.UpdateStatus(RenewalNewStatus, "FPAN Renewal", false))

                // Update related ADR and create Status history
                .then(() =>
                    VV.Form.Template.DocumentsUpdate(
                        RenewalNewStatus,
                        RenewalOldStatus,
                        VV.Form.GetFieldValue("Renewal ID"),
                        formType
                    )
                )

                // Update Main App Status if it's necessary from Renewal updates
                .then(() => 
                    (RenewalNewStatus.toLowerCase() === "renewal accepted") ?
                    VV.Form.Template.UpdateStatus("Renewed", "FPAN", false)
                        .then(() => 
                            VV.Form.Template.DocumentsUpdate(
                                "Renewed",
                                FPANStatus,
                                VV.Form.GetFieldValue("Related Record ID"),
                                mainFormType
                            )
                        ) : 
                    Promise.resolve()
                )

                // Display Success modal
                .then(() => {
                    VV.Form.Global.DisplayModal({
                    Title: "Success",
                    Icon: "success",
                    HtmlContent: "FPAN Renewal status successfully updated.",
                    });
                })

                .catch((error) => {
                    Promise.all([
                        VV.Form.SetFieldValue('FPAN Renewal Status', RenewalOldStatus),
                        VV.Form.SetFieldValue('old FPAN Renewal Status', RenewalOldStatus)
                    ])

                    .then(() => {
                        if (RenewalNewStatus.toLowerCase() === "renewal accepted") {
                            return updateHeaderFpanStatus(FPANStatus);
                        }
                        return Promise.resolve();
                    })

                    .then(() => {
                        console.error("Error updating form:", error);

                        // Check if error was due to DoAjaxFormsave or not
                        if (error.message === 'saveRevisionError') {

                            VV.Form.Global.DisplayModal({
