  });
} else {
  const htmlContent = `<p>Please select at least one "Decision Information" to remove.</p>`;

  VV.Form.Global.DisplayModal({
    HtmlContent: htmlContent,
    Icon: "error",
    Title: "Error",
  });
}

const fieldName = 'Road Construction';
const fieldValue = VV.Form.GetFieldValue(fieldName);
let cleanValue = fieldValue.replace(/[^0-9.]/g, '');
cleanValue = cleanValue.replace(/(\..*?)\..*/g, '$1');
const formattedValue = isNaN(Number(cleanValue)) ? fieldValue : Number(cleanValue).toLocaleString();
if (formattedValue !== fieldValue) {
  VV.Form.SetFieldValue(fieldName, formattedValue).then(() =>
    VV.Form.Template.FormValidation(fieldName)
  );
}
